#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 printf("Child: My PID = %d, Parent PID = %d\n", 
 getpid(), getppid());

 // Replace child program with ls command
 execl("/bin/ls", "ls", "-l", ".", NULL);

 // Only reached if execl fails
 perror("execl failed");
 exit(1);
 }
 else {
 // Parent process
 int status;
 printf("Parent: Created child with PID = %d\n", pid);

 // Wait for child to complete
 waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("Child exited with status: %d\n", 
 WEXITSTATUS(status));
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

int main() {
 int pipefd[2];
 char buffer[100];

 // Create pipe: pipefd[0] = read end, pipefd[1] = write end
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 return 1;
 }

 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }

 if (pid == 0) {
 // Child process - will write to pipe
 close(pipefd[0]); // Close read end

 const char *msg = "Hello from child process!\n";
 write(pipefd[1], msg, strlen(msg));
 close(pipefd[1]); // Close write end to send EOF

 exit(0);
 }
 else {
 // Parent process - will read from pipe
 close(pipefd[1]); // Close write end

 ssize_t bytes_read = read(pipefd[0], buffer, sizeof(buffer));
 if (bytes_read > 0) {
 buffer[bytes_read] = '\0';
 printf("Parent received: %s", buffer);
 }
 close(pipefd[0]); // Close read end

 wait(NULL); // Wait for child
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <sys/select.h>
#include <unistd.h>

int main() {
 fd_set readfds;
 struct timeval timeout;
 int maxfd = STDIN_FILENO; // stdin is fd 0

 while (1) {
 // Clear and set up the file descriptor set
 FD_ZERO(&readfds);
 FD_SET(STDIN_FILENO, &readfds); // Monitor stdin
 FD_SET(pipefd[0], &readfds); // Monitor pipe (if exists)

 // Set timeout to 5 seconds
 timeout.tv_sec = 5;
 timeout.tv_usec = 0;

 int ready = select(maxfd + 1, &readfds, NULL, NULL, &timeout);

 if (ready == -1) {
 perror("select error");
 break;
 }
 else if (ready == 0) {
 printf("Timeout - no data after 5 seconds\n");
 }
 else {
 // Check which fd is ready
 if (FD_ISSET(STDIN_FILENO, &readfds)) {
 char buffer[256];
 if (fgets(buffer, sizeof(buffer), stdin) != NULL) {
 printf("Read from stdin: %s", buffer);
 }
 }
 }
 }
 return 0;
}
